import 'dart:io';
import 'package:flutter/material.dart';
class ProductImagePickerGrid extends StatelessWidget { final List<File> selectedImages; final List<String> existingImageUrls; final VoidCallback onAddImage; final ValueChanged<int> onRemoveSelectedImage; final ValueChanged<int>? onRemoveExistingImage; final bool isLoading; final int maxImages; const ProductImagePickerGrid({super.key, required this.selectedImages, this.existingImageUrls = const [], required this.onAddImage, required this.onRemoveSelectedImage, this.onRemoveExistingImage, this.isLoading = false, this.maxImages = 10}); int get totalCount => selectedImages.length + existingImageUrls.length; @override Widget build(BuildContext context) { final canAdd = totalCount < maxImages; final itemCount = totalCount + (canAdd ? 1 : 0); return Stack(children: [GridView.builder(shrinkWrap: true, physics: const NeverScrollableScrollPhysics(), itemCount: itemCount, gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(crossAxisCount: 3, mainAxisSpacing: 8, crossAxisSpacing: 8), itemBuilder: (context,index){ if(canAdd && index == itemCount-1) return InkWell(onTap: onAddImage, child: DecoratedBox(decoration: BoxDecoration(border: Border.all(color: Theme.of(context).colorScheme.outlineVariant), borderRadius: BorderRadius.circular(12)), child: const Center(child: Icon(Icons.add_photo_alternate_outlined)))); if(index < existingImageUrls.length) return _Tile(onRemove: onRemoveExistingImage == null ? null : () => onRemoveExistingImage!(index), child: Image.network(existingImageUrls[index], fit: BoxFit.cover)); final localIndex = index - existingImageUrls.length; return _Tile(onRemove: () => onRemoveSelectedImage(localIndex), child: Image.file(selectedImages[localIndex], fit: BoxFit.cover)); }), if(isLoading) const Positioned.fill(child: Center(child: CircularProgressIndicator()))]); } }
class _Tile extends StatelessWidget { final Widget child; final VoidCallback? onRemove; const _Tile({required this.child, this.onRemove}); @override Widget build(BuildContext context) => ClipRRect(borderRadius: BorderRadius.circular(12), child: Stack(fit: StackFit.expand, children: [child, if(onRemove!=null) Positioned(top:4,right:4,child: Material(color: Colors.black54, shape: const CircleBorder(), child: InkWell(customBorder: const CircleBorder(), onTap: onRemove, child: const Padding(padding: EdgeInsets.all(4), child: Icon(Icons.close, color: Colors.white, size: 18)))))])); }
